// ==============================
// ① 現在時刻を取得
// ==============================
const now = new Date();

// ==============================
// ② 24時間（ミリ秒）
// ==============================
const ONE_DAY = 24 * 60 * 60 * 1000;

// ==============================
// ③ フィルタ処理
// ==============================
return items.filter(item => {

  // 記事の日時取得（isoDate優先）
  const dateString = item.json.isoDate || item.json.pubDate;

  // 日付がない場合は除外
  if (!dateString) return false;

  const articleDate = new Date(dateString);

  // 時間差を計算
  const diff = now - articleDate;

  // ==============================
  // ④ 24時間以内だけ残す
  // ==============================
  return diff <= ONE_DAY;
});

const html = $json.data || '';

// ==============================
// ① 商品URL抽出（←ここ追加）
// ==============================
const links = [...html.matchAll(/href="(https?:\/\/[^"]+)"/g)]
  .map(m => m[1]);

const productUrl = links.find(url =>
  url.includes('amazon') ||
  url.includes('rakuten') ||
  url.includes('store') ||
  url.includes('shop')
);

// ==============================
// ② テキスト抽出（既存処理）
// ==============================
let text = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]*>/g, '')
  .replace(/[^ぁ-んァ-ン一-龥a-zA-Z0-9。、！？\s]/g, '');

text = text
  .split('\n')
  .map(line => line.trim())
  .filter(line => line.length > 20)
  .join('\n');

text = text.replace(/\s+/g, ' ').trim().slice(0, 3000);

// ==============================
// ③ 出力
// ==============================
return {
  json: {
    link: $('Prepare: Extract Article Link for HTTP').item.json.link,
    cleanText: text,
    product_url: productUrl || ''
  }
};

const segments = $input.first().json.text || [];

const body = segments
  .map((item, index) => {
    let raw = item.json || item;

    let text = '';

    try {
      // ```json を除去
      const cleaned = raw
        .replace(/```json/g, '')
        .replace(/```/g, '')
        .trim();

      const parsed = JSON.parse(cleaned);
      text = parsed.radio_text || '';
    } catch (e) {
      text = '';
    }

    return `第${index + 1}件目です。${text}`;
  })
  .join('\n\n');

const script = `
おはようございます。

今日の仕事術・生産性ニュースを、聞きやすくまとめてお届けします。

${body}

以上、今日の注目ニュースでした。
気になった記事は、あとでSlackのリンクから確認してみてください。
`.trim();

return [
  {
    json: {
      script,
      date: new Date().toISOString().slice(0, 10),
    }
  }
];
